        TRANSACTION_COMPLETE_KUPO_SAY_GOODBYE_TO_DAYS_OF                                                = 7843,  -- Transaction complete, kupo! Say goodbye to days of rummaging through your gobbiebag, and hello to a life of haute hupoture, because you are now the proud owner of a spectacular, snazzy, state-of-the-art mog sack!
        WE_GO_THROUGH_SUCH_PAINS_FOR_YOU_ADVENTURERS                                                    = 7844,  -- We go through such pains for you adventurers, and you would try to procure our products without sufficient funds, kupo? Will you not be content until every last moogle is in the poorhouse!? <Sniff>...<sob>...
