        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                                                    = 7860,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                                                   = 7861,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                                            = 7862,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
