        KUPO_HO_HO_I_KNOW_OF_NO_SUCH                                                                    = 7910,  -- Kupo-ho...ho? I know of no such trial. And given the immense nature of my intellect, that means it could not possibly exist.
        GREETINGS_AND_WELL_MET_I_AM_A_VOIDWATCH                                                         = 7911,  -- Greetings and well met. I am a Voidwatch scientist charged with researching the potential uses of atmacite.
        THOSE_WHO_POSSESS_MAY_COME_TO_ME_TO                                                             = 7912,  -- Those who possess % may come to me to have their hard-won atmacite infused. Stratum abyssite also falls within my domain, so present to me any whose properties you wish to have analyzed.
        AH_I_M_ALSO_AUTHORIZED_TO_TELEPORT_FOLK                                                         = 7913,  -- Ah, I'm also authorized to teleport folk to operation sites. Quite versatile, aren't I?
