        STRATUM_MENU_BACK_TO_THE_TOP_STAGE_1                                                            = 8862,  -- Stratum menu. Back to the top. Stage 1. Stage 2. Stage 3. Stage 4.
        STRATUM_CHANGED_TO                                                                              = 8863,  -- Stratum changed to [Stage 1/Stage 2/Stage 3/Stage 4].
        ABYSSITE_RECEIPT_LEVEL_BACK_TO_THE_TOP_1ST                                                      = 8864,  -- Abyssite receipt level. Back to the top. 1st time. 2nd time and onwards Abyssite evolution. 2nd abyssite evolution and onwards.
        LEVEL_CHANGED_TO                                                                                = 8865,  -- Level changed to [1st time/2nd time and onwards/Abyssite evolution/2nd abyssite evolution and onwards].
        AT_ATTENTION_SOLDIER_I_VE_RECEIVED_AN_URGENT                                                    = 8866,  -- At attention, soldier! I've received an urgent alarum calling our best men to arms, and guess whose name is listed front and center? You're to report to Jeuno for further orders immediately.
        DO_WE_HAVE_A_MISUNDERSTANDING_HERE_SOLDIER_I                                                    = 8867,  -- Do we have a misunderstanding here, soldier? I said, immediately. You'll get your briefing at the palace, not from me. Pick up those legs and get a move on!
        DO_WE_HAVE_A_MISUNDERSTANDING_HERE_SOLDIER_I_2                                                  = 8868,  -- Do we have a misunderstanding here, soldier? I said, immediately. You'll get your briefing at the palace, not from me.
        THAT_SAID_IN_THESE_TIMES_OF_WAR_ENTRY                                                           = 8869,  -- That said, in these times of war, entry to the Grand Duchy is limited to authorized personnel. Show your alarum at the bulwark gate in Sauromugue and one of our men will see you through.
        TIME_IS_SHORT_SO_PICK_UP_THOSE_LEGS                                                             = 8870,  -- Time is short, so pick up those legs and get a move on, soldier!
        THAT_SAID_IN_THESE_TIMES_OF_WAR_ENTRY_2                                                         = 8871,  -- That said, in these times of war, entry to the Grand Duchy is limited to authorized personnel. Show your alarum at the bulwark gate just over there and one of our men will see you through.
        EXCELLENT_WORK_YOU_SERVE_THE_VOIDWATCH_WELL_YOUR                                                = 8872,  -- Excellent work, %. You serve the Voidwatch well. Your presence has been requested in the Grand Duchy once more. Make your way there with all speed.
        AS_BEFORE_A_FULL_BRIEFING_WILL_BE_CONDUCTED                                                     = 8873,  -- As before, a full briefing will be conducted upon your arrival at the palace.
        THAT_IS_ALL_YOU_RE_DISMISSED_SOLDIER                                                            = 8874,  -- That is all. You're dismissed, soldier!
        AS_BEFORE_A_FULL_BRIEFING_WILL_BE_CONDUCTED_2                                                   = 8875,  -- As before, a full briefing will be conducted upon your arrival at the palace. Show your alarum at the bulwark gate at Sauromugue and one of our men will see you through the checkpoint.
        THAT_IS_ALL_YOU_RE_DISMISSED_SOLDIER_2                                                          = 8876,  -- That is all. You're dismissed, soldier!
