        WHERE_S_YOUR_SOLDIER_I_LL_NEED_TO                                                               = 8878,  -- Where's your %, soldier? I'll need to see one before I can authorize your participation in the [Jeuno/Qufim] Voidwatch jurisdiction.
        ARE_ISSUED_ONLY_TO_THOSE_BRAVE_MEN_AND                                                          = 8879,  -- % are issued only to those brave men and women who have distinguished themselves in regional Voidwatch efforts.
        PROVE_YOURSELF_CAPABLE_IN_THE_THREE_NATIONS_AND                                                 = 8880,  -- Prove yourself capable in the three nations, and you can rest assured that your abilities won't go overlooked. Keep fighting the good fight, soldier!
        REPORTING_FOR_COMBAT_ARE_YOU_YES_THIS_OF                                                        = 8881,  -- Reporting for combat, are you? Yes, this % of yours appears to be in order. Welcome aboard!
        I_SUSPECT_YOU_VE_ALREADY_BEEN_BRIEFED_ABOUT                                                     = 8882,  -- I suspect you've already been briefed about the use of %, but protocol dictates that I ask if you are in need of a review. What will it be, soldier?
        WHAT_WILL_IT_BE_SOLDIER_READY_FOR_BATTLE                                                        = 8883,  -- What will it be, soldier? Ready for battle, sir! I need a briefing, sir!
        NOW_THAT_S_WHAT_I_LIKE_TO_HEAR                                                                  = 8884,  -- Now that's what I like to hear, soldier!
