        OPERATIONS_ARE_PRESENTLY_UNDERWAY_WHILE_PLANAR_RIFTS_HAVE_2                                     = 8886,  -- Operations are presently underway [in Batallia Downs/in Batallia Downs/in the Eldieme Necropolis/in the Eldieme Necropolis]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_WHILE_PLANAR_RIFTS_HAVE_3                                     = 8887,  -- Operations are presently underway [in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_WHILE_PLANAR_RIFTS_HAVE_4                                     = 8888,  -- Operations are presently underway [in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel]. While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        OPERATIONS_ARE_PRESENTLY_UNDERWAY_AT_QUFIM_ISLAND_DELKFUTT                                      = 8889,  -- Operations are presently underway at Qufim Island, Delkfutt's Tower, and Behemoth's Dominion.
        WHILE_PLANAR_RIFTS_HAVE_BEEN_REPORTED_IN_OTHER                                                  = 8890,  -- While planar rifts have been reported in other areas, we've yet to discover how to engage Voidwalkers there.
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_4                                                 = 8891,  -- At this time, we request your participation in the operation [in Batallia Downs/in Batallia Downs/in the Eldieme Necropolis/in the Eldieme Necropolis/in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest/in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel/on Qufim Island/in Delkfutt's Tower/in Behemoth's Dominion].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_5                                                 = 8892,  -- At this time, we request your participation in the operation [in Batallia Downs/in Batallia Downs/in the Eldieme Necropolis/in the Eldieme Necropolis].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_6                                                 = 8893,  -- At this time, we request your participation in the operation [in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_7                                                 = 8894,  -- At this time, we request your participation in the operation [in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel].
        AT_THIS_TIME_WE_REQUEST_YOUR_PARTICIPATION_IN_8                                                 = 8895,  -- At this time, we request your participation in the operations at Qufim Island, Delkfutt's Tower, and Behemoth's Dominion.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_4                                                = 8896,  -- [Operations are set to commence/Operations are currently underway] [in Batallia Downs/in Batallia Downs/in the Eldieme Necropolis/in the Eldieme Necropolis/in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest/in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel/on Qufim Island/in Delkfutt's Tower/in Behemoth's Dominion]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_5                                                = 8897,  -- [Operations are set to commence/Operations are currently underway] [in Batallia Downs/in Batallia Downs/in the Eldieme Necropolis/in the Eldieme Necropolis/in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest/in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel/on Qufim Island/in Delkfutt's Tower/in Behemoth's Dominion]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_6                                                = 8898,  -- [Operations are set to commence/Operations are currently underway] [in Rolanberry Fields/in Rolanberry Fields/in the Crawlers' Nest/in the Crawlers' Nest]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_7                                                = 8899,  -- [Operations are set to commence/Operations are currently underway] [in Sauromugue Champaign/in Sauromugue Champaign/in the Garlaige Citadel/in the Garlaige Citadel]. Your presence there would be of tremendous aid to our efforts.
        YOUR_PRESENCE_THERE_WOULD_BE_OF_TREMENDOUS_AID_8                                                = 8900,  -- [Operations are set to commence at/Operations are currently underway at] [Qufim Island/Delkfutt's Tower/Behemoth's Dominion]. Your presence there would be of tremendous aid to our efforts.
        OPERATIONS_REMAIN_UNDERWAY_AT_YOUR_PRESENCE_THERE_WOULD                                         = 8901,  -- Operations remain underway at [Qufim Island,/Delkfutt's Tower,/Qufim Island./Delkfutt's Tower./Behemoth's Dominion.][ Delkfutt's Tower,/ and Behemoth's Dominion./ and Delkfutt's Tower./][ and Behemoth's Dominion./] Your presence there would be of tremendous aid to our efforts.
        HOLD_IT_RIGHT_THERE_SOLDIER_A_SUMMONS_JUST                                                      = 8902,  -- Hold it right there, soldier! A summons just came in from the Grand Duchy, and it's got your name on it. The envoy said it's an urgent matter, so I suggest you get moving.
        WE_VE_BEEN_LOOKING_FOR_YOU_SOLDIER_I                                                            = 8903,  -- We've been looking for you, soldier. I've got a summons from the Grand Duchy here, and just look at the name on it: %. Our messenger said it's an urgent matter, so I suggest you ready yourself and depart immediately.
        YOU_MAY_ALSO_UNDERTAKE_THIS_OPERATION_AT_BEAUCEDINE                                             = 8904,  -- You may also undertake this operation at Beaucedine Glacier.
        HOW_MANY_CRUOR                                                                                  = 8905,  -- How many? (Cruor: #)
        YOU_MAY_PURCHASE_UP_TO_AT_A_TIME                                                                = 8906,  -- You may purchase up to # at a time.
        HAPPY_9TH_VANA_VERSARY_KUPO_I_VE_RECEIVED                                                       = 8907,  -- Happy 9th Vana'versary, kupo! I've received a proper profusion of congratulatory letters from all over the land!
        NOW_KNOWING_HOW_YOU_ADVENTURERS_ARE_BUSIER_THAN                                                 = 8908,  -- Now, knowing how you adventurers are busier than breadwinner bees, I've chosen only the choicest missive to recite. Here goes! Ahem!
        ESTEEMED_ADVENTURERS_OF_VANA_DIEL_IN_THE_WAKE                                                   = 8909,  -- Esteemed adventurers of Vana'diel, In the wake of your passage blows the wind of peace and prosperity. In the sparkling of your eyes we behold a future bright and fair.
        ON_BEHALF_OF_ALL_JEUNO_I_EXTEND_TO                                                              = 8910,  -- On behalf of all Jeuno, I extend to you my heartfelt gratitude. The Duchy is ever indebted to you, her gates ever open to you. Now and for all time.
        ARCHDUKE_KAM_LANAUT                                                                             = 8911,  -- Archduke Kam'lanaut
        HOW_S_ABOUT_THAT_EH_SUCH_A_HIGH                                                                 = 8912,  -- How's about that, eh? Such a high heaping of praise from Jeuno's head honcho himself is a right rarity, kupo! Why, I was nigh swept off my wings when I first read the letter!
        OHO_YOUR_EVIDENTLY_EXPECTANT_EXPRESSION_TELLS_ME_YOU                                            = 8913,  -- Oho! Your evidently expectant expression tells me you know what's coming next!
        TADA_DECK_YOURSELF_IN_THESE_DANDY_DUDS_AND                                                      = 8914,  -- Tada! Deck yourself in these dandy duds and set free your festive frame of mind, kupopo!
        KUPO_WHOA_LOOKING_DECIDEDLY_DEBONAIR_DAZZLING_THERE_KUPO                                        = 8915,  -- Kupo-whoa! Looking decidedly debonair/dazzling] there, kupo!
        THAT_REMINDS_ME_WE_RE_RUNNING_LOW_ON                                                            = 8916,  -- That reminds me, we're running low on materials needed to make the garments. Deliveries of custom-made fabric, leather, and metal trimmings haven't arrived in quite some time, kupo.
        WHAT_COULD_POSSIBLY_BE_CAUSING_THE_DELAY_I                                                      = 8917,  -- What could possibly be causing the delay? I'd go and see for myself, but for my permanent posting here, kupo...
        HM_WHY_AREN_T_YOU_SPORTING_YOUR_YOU                                                             = 8918,  -- Hm? Why aren't you sporting your %? You can't just amble about in awkwardly arranged attire, kupo!
        HEY_WHY_AREN_T_YOU_CLOTHED_CONGRUOUSLY_WITH                                                     = 8919,  -- Hey, why aren't you clothed congruously with the celebration, kupo?
        WHAT_DON_T_HAVE_YOU_SAY                                                                         = 8920,  -- What? Don't have %, you say?
        I_CAN_T_ALLOW_YOU_TO_AMBLE_ABOUT                                                                = 8921,  -- I can't allow you to amble about in awkwardly arranged attire, kupo! Here, quickly slip this on before you become the laughingstock of mooglekind!
        WHAT_YOU_HAVE_NEITHER_NOR_KUPO_WE_BARELY                                                        = 8922,  -- What? You have neither % nor %, kupo!? We barely have enough to hand out, yet you go misplacing yours! Utterly unbelievable!
        SIGH_LISTEN_KUPO_I_LIKE_YOU_SO_I                                                                = 8923,  -- <Sigh>... Listen, kupo. I like you, so I'm going to issue you a replacement set. Just don't go blabbing to your buddies about the boon, all right?
        HMMM_WE_RE_STILL_SHORT_ON_AND_KUPO                                                              = 8924,  -- Hmmm... We're still short on % and %, kupo.
        HMMM_WE_RE_STILL_SHORT_ON_KUPO                                                                  = 8925,  -- Hmmm... We're still short on %, kupo.
        KUPOPO_YOU_VE_OBTAINED_THE_OVERDUE_OBJECTS_FOR                                                  = 8926,  -- Kupopo!? You've obtained the overdue objects for me, you say!?
        OH_DELIRIOUSLY_DELIGHTFUL_DAY_WITHOUT_ADO_PRAY_PRESENT                                          = 8927,  -- Oh, deliriously delightful day! Without ado, pray present the procured pieces to me!
        HANDS_THE_MATERIALS_TO_THE_EXCITED_MOOGLE                                                       = 8928,  -- % hands the materials to the excited moogle.
        WONDERFUL_I_CAN_FAIRLY_FIND_NO_FAULT_WITH                                                       = 8929,  -- Wonderful! I can fairly find no fault with the items, kupo!
        YOU_HAVE_DONE_US_MOOGLES_A_GREAT_SERVICE                                                        = 8930,  -- You have done us moogles a great service! Truly, you are deserving of the noble (and non-existent) Adventurer of the Anniversary Award, kupo!
        PLEASE_ACCEPT_THIS_AS_A_TINY_TOKEN_OF                                                           = 8931,  -- Please accept this as a tiny token of my gargantuan gratitude.
        THE_ADVENTURER_APPRECIATION_CAMPAIGN_WILL_RUN_FOR_A                                             = 8932,  -- The Adventurer Appreciation Campaign will run for a limited time only. Be sure to make the most of it while it lasts, kupo!
        UWAAAH_I_I_M_GOING_TO_BE_DEALT                                                                  = 8933,  -- Uwaaah! I...I'm going to be dealt a d-d-dreadful death, kupo!
        LOOK_I_M_KEEPING_THE_CREATURE_PROVOKED_SO                                                       = 8934,  -- Look, I'm keeping the creature provoked, so there's nothing to be afraid of. You can stop hiding in mommy's skirt now.
        UWAAAH_A_MONSTROUS_MOOGLE_EATING_MOMMY_LIZARD_DON                                               = 8935,  -- Uwaaah! A monstrous moogle-eating mommy lizard! Don't let it n-n-near me, kupo!
        A_MONSTROUS_MOOGLE_EATING_WHAT_ARE_YOU_EVEN                                                     = 8936,  -- A monstrous moogle-eating...what? Are you even listening to me? Nothing's going to hurt you, so get a grip already!
        UWAAAH_UM_I_MEAN_IS_THAT_N_N                                                                    = 8937,  -- Uwaaah! Um...I mean, is that n-n-novennial attire you're sporting? It looks suitably swanky on you, k-k-kupo!
        APPRISES_THE_MOOGLE_OF_THE_MATERIAL_SHORTAGE                                                    = 8938,  -- % apprises the moogle of the material shortage.
